namespace GlitchCompiler.Anomalies { public sealed class SyntaxShiftAnomaly:IAnomaly { private AnomalyContext context; public string Id=>"syntax-shift"; public void OnTrigger(AnomalyContext value){context=value;context.WriteCode(context.ReadCode().Replace("TURN","BURN"));context.ShowOverlay("語法重載","使用搜尋與取代，將 BURN 全部改回 TURN。");} public bool CheckResolved()=>!context.ReadCode().Contains("BURN"); public void OnResolve(){context.HideOverlay();context.AddTime(10);} public void OnCleanup(){} } }
